import type { HTMLArkProps } from '@ark-ui/react/factory';
import { ark } from '@ark-ui/react/factory';
import { clsx } from 'clsx';
import { forwardRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './Heading.module.css';

type HeadingSize = 'xs' | 'sm' | 'md' | 'lg' | 'xl' | '2xl';
type HeadingWeight = 'regular' | 'medium' | 'semibold' | 'bold';
type HeadingElement = 'h1' | 'h2' | 'h3' | 'h4' | 'h5' | 'h6';
type HeadingRootProps = HTMLArkProps<'h1'> & {
  as?: HeadingElement;
  size?: HeadingSize;
  weight?: HeadingWeight;
};

const elements = {
  h1: ark.h1,
  h2: ark.h2,
  h3: ark.h3,
  h4: ark.h4,
  h5: ark.h5,
  h6: ark.h6,
} as const;

const HeadingRoot = forwardRef<HTMLHeadingElement, HeadingRootProps>(function HeadingRoot(
  { as, asChild, size, weight = 'semibold', className, ...props },
  ref,
) {
  const Element = elements[as ?? 'h1'] as typeof ark.h1;

  return (
    <Element
      ref={ref}
      asChild={asChild}
      data-scope="heading"
      data-part="root"
      data-slot="heading-root"
      data-size={size}
      data-weight={weight}
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const Heading = Object.assign(HeadingRoot, {
  Root: HeadingRoot,
});

export { Heading };

@layer moduix.components {
  .root {
    --_heading-font-size: var(--moduix-heading-font-size-2xl, var(--moduix-text-3xl));
    --_heading-line-height: var(
      --moduix-heading-line-height-2xl,
      var(--moduix-line-height-text-3xl)
    );
    --_heading-font-weight: var(
      --moduix-heading-font-weight-semibold,
      var(--moduix-weight-semibold)
    );

    margin: 0;
    color: var(--moduix-heading-color, var(--moduix-color-foreground));
    font-family: var(--moduix-heading-font-family, inherit);
    font-size: var(--moduix-heading-font-size, var(--_heading-font-size));
    font-weight: var(--moduix-heading-font-weight, var(--_heading-font-weight));
    line-height: var(--moduix-heading-line-height, var(--_heading-line-height));
    letter-spacing: var(--moduix-heading-letter-spacing, 0);
    text-wrap: var(--moduix-heading-text-wrap, balance);
    overflow-wrap: break-word;

    &:is(h6):not([data-size]),
    &[data-size='xs'] {
      --_heading-font-size: var(--moduix-heading-font-size-xs, var(--moduix-text-sm));
      --_heading-line-height: var(
        --moduix-heading-line-height-xs,
        var(--moduix-line-height-text-sm)
      );
    }

    &:is(h5):not([data-size]),
    &[data-size='sm'] {
      --_heading-font-size: var(--moduix-heading-font-size-sm, var(--moduix-text-md));
      --_heading-line-height: var(
        --moduix-heading-line-height-sm,
        var(--moduix-line-height-text-md)
      );
    }

    &:is(h4):not([data-size]),
    &[data-size='md'] {
      --_heading-font-size: var(--moduix-heading-font-size-md, var(--moduix-text-lg));
      --_heading-line-height: var(
        --moduix-heading-line-height-md,
        var(--moduix-line-height-text-lg)
      );
    }

    &:is(h3):not([data-size]),
    &[data-size='lg'] {
      --_heading-font-size: var(--moduix-heading-font-size-lg, var(--moduix-text-xl));
      --_heading-line-height: var(
        --moduix-heading-line-height-lg,
        var(--moduix-line-height-text-xl)
      );
    }

    &:is(h2):not([data-size]),
    &[data-size='xl'] {
      --_heading-font-size: var(--moduix-heading-font-size-xl, var(--moduix-text-2xl));
      --_heading-line-height: var(
        --moduix-heading-line-height-xl,
        var(--moduix-line-height-text-2xl)
      );
    }

    &[data-size='2xl'] {
      --_heading-font-size: var(--moduix-heading-font-size-2xl, var(--moduix-text-3xl));
      --_heading-line-height: var(
        --moduix-heading-line-height-2xl,
        var(--moduix-line-height-text-3xl)
      );
    }

    &[data-weight='regular'] {
      --_heading-font-weight: var(
        --moduix-heading-font-weight-regular,
        var(--moduix-weight-regular)
      );
    }

    &[data-weight='medium'] {
      --_heading-font-weight: var(--moduix-heading-font-weight-medium, var(--moduix-weight-medium));
    }

    &[data-weight='bold'] {
      --_heading-font-weight: var(--moduix-heading-font-weight-bold, var(--moduix-weight-bold));
    }
  }
}
